class SecureAuthenticationInterceptor(ServerInterceptor):
    """
    RECOMMENDED: Authentication interceptor that requires auth for admin
    endpoints and validates admin role claims.

    Only truly public endpoints (health, metrics) skip auth.
    """

    # Only genuinely public endpoints skip auth
    PUBLIC_METHODS = {
        "/grpc.health.v1.Health/Check",
        "/grpc.health.v1.Health/Watch",
    }

    PUBLIC_PREFIXES = (
        "/grpc.health.v1.Health/",
        "/metrics",
        "/health",
    )

    # Admin methods require elevated privileges
    ADMIN_PREFIXES = (
        "/admin/",
    )

    def __init__(self, token_validator: TokenValidator):
        self._validator = token_validator

    def _is_public(self, method: str) -> bool:
        if method in self.PUBLIC_METHODS:
            return True
        return any(method.startswith(p) for p in self.PUBLIC_PREFIXES)

    def _is_admin(self, method: str) -> bool:
        return any(method.startswith(p) for p in self.ADMIN_PREFIXES)

    def intercept_service(self, continuation, handler_call_details):
        method = handler_call_details.method

        if self._is_public(method):
            return continuation(handler_call_details)

        # Extract and validate token
        token = TokenValidator.extract_token(
            handler_call_details.invocation_metadata or []
        )

        if not token:
            return self._abort(grpc.StatusCode.UNAUTHENTICATED, "Token required")

        try:
            claims = self._validator.validate(token)
        except ValueError as e:
            return self._abort(grpc.StatusCode.UNAUTHENTICATED, str(e))

        # Admin methods require admin role
        if self._is_admin(method):
            roles = claims.get("roles", [])
            if "admin" not in roles:
                logger.warning(
                    f"Non-admin user '{claims.get('sub')}' attempted "
                    f"admin method: {method}"
                )
                return self._abort(
                    grpc.StatusCode.PERMISSION_DENIED,
                    "Admin role required"
                )
            logger.info(f"Admin access granted to '{claims.get('sub')}' for {method}")

        return continuation(handler_call_details)

    def _abort(self, code, details):
        def handler(request, context):
            context.abort(code, details)
        return grpc.unary_unary_rpc_method_handler(handler)


